import React from "react";
import { useNavigate } from "react-router-dom";

export default function AddNew() {
  const navigate = useNavigate();

  return (
    <div
      style={{
        padding: 30,
        fontFamily: "Segoe UI",
        background: "#f5f5f5",
        minHeight: "100vh",
      }}
    >
      <h2 style={{ textAlign: "center", marginBottom: 30, color: "#0f9d58" }}>
        Add New Expense
      </h2>

      <div
        style={{
          display: "flex",
          justifyContent: "center",
          gap: 40,
          marginTop: 40,
        }}
      >
        {/* TRAVEL EXPENSE CARD */}
        <div
          onClick={() => navigate("/add/travel")}
          style={cardStyle()}
        >
          <h3 style={{ marginBottom: 10 }}>🚌 Travel Expense</h3>
          <p>Add new travel records, view history, edit or delete.</p>
        </div>

        {/* TICKET EXPENSE CARD */}
        <div
          onClick={() => navigate("/add/ticket")}
          style={cardStyle()}
        >
          <h3 style={{ marginBottom: 10 }}>🎫 Ticket Expense</h3>
          <p>Manage ticket-related expenses and see reports.</p>
        </div>
      </div>
    </div>
  );
}

function cardStyle() {
  return {
    width: "280px",
    background: "white",
    padding: 25,
    borderRadius: 12,
    boxShadow: "0px 4px 15px rgba(0,0,0,0.1)",
    cursor: "pointer",
    textAlign: "center",
    transition: "0.2s",
  };
}
